#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int n; scanf("%d", &n);
        int arr[1000];
        for(int i=0;i<n;i++) scanf("%d", &arr[i]);
        bool ok = true;
        for(int i=0;i<n && ok;i++){
            int l = 2*i + 1;
            int r = 2*i + 2;
            if(l < n && arr[l] < arr[i]) ok = false;
            if(r < n && arr[r] < arr[i]) ok = false;
        }
        printf(ok ? "Yes\n" : "No\n");
    }
    return 0;
}

